(function(){'use strict';document.addEventListener('DOMContentLoaded',function(){var e=document.querySelector('[data-fc-carousel]');if(!e)return;var s=new Splide(e,{type:'slide',perPage:4,perMove:1,gap:'20px',arrows:false,pagination:false,breakpoints:{1024:{perPage:3},768:{perPage:2}}});s.mount();var p=document.querySelector('[data-fc-prev]'),n=document.querySelector('[data-fc-next]');if(p)p.addEventListener('click',function(){s.go('<')});if(n)n.addEventListener('click',function(){s.go('>')})})})();
